import React from "react";
// import React from "./Phones";

function Card(props) {
  return (
    <div className="card">
      <div className="top">
        <h2 className="name">{props.name}</h2>
        {/* <img className="circle-img" src={props.img} /> */}
      </div>
      <div className="bottom">
        <p className="info">{props.price}</p>
        <p className="info">{props.desc}</p>
      </div>
    </div>
  );
}

export default Card;