import React from "react";
import  Typography  from "@mui/material/Typography"; 
import Button from "@mui/material/Button";
import  Container  from "@mui/material/Container";
import Stack from "@mui/material/Stack";
import TextField  from "@mui/material/TextField";
import f from "./img/f.webp";
import i from "./img/i.png";
import x from "./img/x.jpg";
import Email from "./Email";


class Contact extends React.Component {
   constructor(props) {
    super(props);
    //  Setting the initial state
    this.state = {
    
      number: "xxxxxxxxxxx",
      email: "xxxxxxxxx@gmail.com",
    };
       // Binding this keyword
    this.updateState = this.updateState.bind(this);
  }
   updateState() {
    // Changing state to the new one (old one above)
    this.setState({
      number: "12345678901",
      email: "PhoneShop@gmail.com",
    });
  }
    render() {
    return (
      <div>
        <p>{this.state.number}</p>
        <p>{this.state.email}</p>
        <button onClick={this.updateState}>Show contact details</button>
        <br></br>

<TextField id="outlined-basic" label="Name" variant="outlined" />
<TextField id="filled-basic" label="Email" variant="filled" />
<TextField id="standard-basic" label="Message" variant="standard" />
<Button variant="text">Submit</Button>

  <br> 
  </br>
  <h4>Follow us here</h4>
  <img src={f} height={100} width={100} />
  <img src={i} height={100} width={100} />
  <img src={x} height={100} width={100} />


         <footer>
		<div class="container">
			<div class="footer_content">
			</div>
				<div class="footer_content">
					<div class="footer_content">
					<h3>The Phone House</h3>
				</div>
			</div>
				<div class="footer_content">
					<div class="footer_content">
				
				</div>
			</div>
		</div>
	</footer> 
      </div>
    );
  }
}
export default Contact;
